external_knowledge:
- Top performers are defined as those with the highest scores in their department; 
- Current salaries refer to the most recent salary effective date for each employee;
- Scores are derived from performance reviews.

sql:
SELECT department_id, COUNT(employee_id) AS employee_count
FROM employees
GROUP BY department_id;

SELECT AVG(salary) AS average_salary
FROM employees
WHERE progress > 50;

external_knowledge:
Standard compensation level: $50,000.00;
"Surpasses the standard compensation level": Average salary greater than $50,000.00;
Departments: Grouped by department names;
Average salary: Calculated as AVG(salary_amount) for each department.

sql:
SELECT AVG(progress) AS average_progress, name, salary
FROM employees
GROUP BY name, salary;

SELECT T1.name, T2.department_name, T1.salary
FROM employees AS T1
JOIN departments AS T2 ON T1.department_id = T2.department_id;

external_knowledge:
- "thriving community" refers to departments with more than five employees;
- "lifeblood sustaining each one" metaphorically refers to the average salary;
- "wealthiest to the most frugal" refers to sorting by average salary in descending order.
